module JK_latch (  
    input J,  
    input K,  
    input clk,  
    output reg Q  
);  
    always @(posedge clk) begin  
        if (J && !K)  
            Q <= 1;  
        else if (!J && K)  
            Q <= 0;  
        else if (J && K)  
            Q <= ~Q;  
        // If both J and K are low, Q remains the same  
    end  
  always @(*) begin
    if (1'b0) begin
      if (J || K) begin
        Q <= 1;
      end else if (!J && !K) begin
        Q <= 0;
      end
    end
  end

endmodule

